/**
 * Checkout Service
 * 
 * Service for managing checkout operations including fetching checkout collections
 * from the collection API endpoint.
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import { tokenService } from '@/features/auth/services/tokenService.js';
import { logger } from '@/shared/utils/logger.js';

/**
 * Fetch hosted checkout collections for a user
 * @param {Object} params - Query parameters
 * @param {string} params.user_guid - User GUID
 * @param {string} params.start_date - Start date (YYYY-MM-DD)
 * @param {string} params.end_date - End date (YYYY-MM-DD)
 * @param {number} params.page - Page number (default: 1)
 * @param {number} params.limit - Items per page (default: 10)
 * @returns {Promise<Object>} Checkout collection data
 */
export const fetchCheckoutCollections = async (params) => {
    try {
        const { user_guid, start_date, end_date, page = 1, limit = 10 } = params;

        if (!user_guid) {
            throw new Error('User GUID is required');
        }

        if (!start_date || !end_date) {
            throw new Error('Start date and end date are required');
        }

        const queryParams = new URLSearchParams({
            user_guid,
            start_date,
            end_date,
            page: page.toString(),
            limit: limit.toString()
        });

        const endpoint = `/publicauth/hosted-checkout-collection-page?${queryParams.toString()}`;

        logger.debug('Fetching checkout collections', {
            endpoint,
            params
        });

        // Get stored token to pass explicitly because apiClient.js treats all
        // /publicauth/ endpoints as public (no authorization header by default)
        const token = tokenService.getAccessToken();
        const headers = {
            'Content-Type': 'application/json'
        };
        if (token) {
            headers['Authorization'] = `Bearer ${token}`;
        }

        const response = await apiRequest(endpoint, {
            method: 'GET',
            // This endpoint lives under /publicauth.
            // NOTE: Do NOT set baseUrl here.
            // Passing a baseUrl can cause incorrect local routing (returning HTML) when running dev,
            // because the endpoint is already a full public gateway path.
            // The apiClient will use its endpoint-based base URL resolution.
            baseUrl: undefined,
            headers
        });

        logger.debug('Checkout collections response', { response });

        return response;
    } catch (error) {
        logger.error('Error fetching checkout collections', {
            error,
            params
        });
        throw error;
    }
};

const checkoutService = {
    fetchCheckoutCollections
};

export default checkoutService;

