/**
 * Checkout Page
 * 
 * Dedicated checkout page for payment collection and transactions.
 * Supports both individual and business users with customized views.
 * Displays checkout history, allows users to generate new checkout links,
 * and manage payment settings.
 */

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import '/styles/pages/CheckoutPage.css';
import { MetricCard, LoadingSpinner } from '@/shared/components';
import GenerateCheckoutLinkModal from '@/features/checkout/components/GenerateCheckoutLinkModal.jsx';
import { tokenService } from '@/features/auth/services';
import { logger } from '@/shared/utils/logger.js';
import checkoutService from '@/features/checkout/services/checkoutService.js';
import { useToast } from '@/app/providers/ToastContext.jsx';

// ---------------------------------------------------------------------------
// Checkout Details Modal — separate component so createPortal works cleanly
// ---------------------------------------------------------------------------
const CheckoutDetailsModal = ({ checkout, onClose, formatCurrency, formatDate, parseInvoiceItems, getStatusStyle, handleCopyLink }) => {
  if (!checkout) return null;

  const c = checkout;
  const statusStyle = getStatusStyle(c.status || c.Status);
  const invoiceItems = parseInvoiceItems(c.invoice_items);
  const customerName = c.first_name || c.last_name
    ? `${c.first_name || ''} ${c.last_name || ''}`.trim()
    : c.customer_name || c.customer || c.email_name || 'N/A';
  const sessionUrl = c.session_url || c.sessionUrl;

  const modal = (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 100000,
        background: 'rgba(0,0,0,0.55)',
        backdropFilter: 'blur(4px)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '20px'
      }}
      onClick={onClose}
    >
      <div
        style={{
          background: 'var(--card)',
          borderRadius: '16px',
          width: '100%',
          maxWidth: '560px',
          maxHeight: '90vh',
          overflowY: 'auto',
          boxShadow: '0 25px 50px rgba(0,0,0,0.35)',
          border: '1px solid var(--border-primary)'
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Modal Header */}
        <div style={{
          padding: '20px 24px 16px',
          borderBottom: '1px solid var(--border-primary)',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <div>
            <h3 style={{ margin: 0, fontSize: '18px', fontWeight: 700, color: 'var(--text-primary)' }}>
              Checkout Details
            </h3>
            <p style={{ margin: '4px 0 0', fontSize: '12px', color: 'var(--text-muted)' }}>
              {c.reference_id || c.referenceid || c.id}
            </p>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <span style={{
              padding: '5px 12px',
              borderRadius: '20px',
              fontSize: '12px',
              fontWeight: 700,
              textTransform: 'uppercase',
              background: statusStyle.background,
              color: statusStyle.color
            }}>
              {statusStyle.text}
            </span>
            <button
              onClick={onClose}
              style={{
                background: 'var(--bg-secondary)',
                border: 'none',
                borderRadius: '8px',
                width: '32px',
                height: '32px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: 'pointer',
                color: 'var(--text-muted)'
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>close</span>
            </button>
          </div>
        </div>

        {/* Modal Body */}
        <div style={{ padding: '20px 24px', display: 'flex', flexDirection: 'column', gap: '20px' }}>

          {/* Amount Banner */}
          <div style={{
            background: 'var(--bg-secondary)',
            borderRadius: '12px',
            padding: '16px',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center'
          }}>
            <div>
              <div style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Amount</div>
              <div style={{ fontSize: '28px', fontWeight: 800, color: 'var(--text-primary)', marginTop: '4px' }}>
                {formatCurrency(c.amount, c.currency)}
              </div>
            </div>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600 }}>Payment Mode</div>
              <div style={{ fontSize: '14px', fontWeight: 700, color: 'var(--text-primary)', textTransform: 'capitalize', marginTop: '4px' }}>
                {c.payment_mode || c.paymentMode || 'N/A'}
              </div>
            </div>
          </div>

          {/* Info Grid */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
            {[
              { icon: 'person', label: 'Customer', value: customerName },
              { icon: 'email', label: 'Email', value: (() => { const e = c.email_name || c.email || ''; return e && e.toLowerCase() !== 'test@ismartghana.com' ? e : 'N/A'; })() },
              { icon: 'phone', label: 'Phone', value: c.phonenumber || c.phone_number || c.phone || 'N/A' },
              { icon: 'label', label: 'Narration', value: c.narration || 'Payment Collection' },
              { icon: 'payment', label: 'Payment Type', value: c.payment_type || c.paymentType || 'N/A' },
              { icon: 'storefront', label: 'Origin', value: c.origin || 'N/A' },
              { icon: 'schedule', label: 'Session Timer', value: c.session_timer ? `${Math.floor(c.session_timer / 60)} min` : 'N/A' },
              { icon: 'calendar_today', label: 'Created', value: formatDate(c.created_at || c.createdAt) },
            ].map(({ icon, label, value }) => (
              <div key={label} style={{ background: 'var(--bg-secondary)', borderRadius: '8px', padding: '10px 12px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '5px', marginBottom: '4px' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '14px', color: 'var(--accent)' }}>{icon}</span>
                  <span style={{ fontSize: '11px', fontWeight: 600, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.4px' }}>{label}</span>
                </div>
                <div style={{ fontSize: '13px', fontWeight: 600, color: 'var(--text-primary)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{value}</div>
              </div>
            ))}
          </div>

          {/* Checkout URL */}
          {sessionUrl && (
            <div style={{ background: 'var(--bg-secondary)', borderRadius: '8px', padding: '12px' }}>
              <div style={{ fontSize: '11px', fontWeight: 600, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.4px', marginBottom: '8px', display: 'flex', alignItems: 'center', gap: '5px' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '14px', color: 'var(--accent)' }}>link</span>
                Checkout URL
              </div>
              <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                <span style={{ fontSize: '12px', color: 'var(--text-secondary)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>{sessionUrl}</span>
                <button
                  onClick={() => handleCopyLink(sessionUrl)}
                  style={{
                    flexShrink: 0,
                    padding: '6px 12px',
                    borderRadius: '6px',
                    border: '1px solid var(--border-secondary)',
                    background: 'var(--card)',
                    color: 'var(--text-primary)',
                    fontSize: '12px',
                    fontWeight: 600,
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '4px'
                  }}
                >
                  <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>content_copy</span>
                  Copy
                </button>
              </div>
            </div>
          )}

          {/* Invoice Items */}
          {invoiceItems.length > 0 && (
            <div>
              <div style={{ fontSize: '13px', fontWeight: 700, color: 'var(--text-primary)', marginBottom: '10px', display: 'flex', alignItems: 'center', gap: '6px' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '16px', color: 'var(--accent)' }}>receipt_long</span>
                Invoice Items
              </div>
              <div style={{ borderRadius: '8px', overflow: 'hidden', border: '1px solid var(--border-primary)' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '13px' }}>
                  <thead>
                    <tr style={{ background: 'var(--bg-secondary)' }}>
                      {['Description', 'Qty', 'Unit Price', 'Total'].map(h => (
                        <th key={h} style={{
                          padding: '10px 12px',
                          textAlign: h === 'Description' ? 'left' : 'right',
                          fontSize: '11px',
                          fontWeight: 700,
                          color: 'var(--text-muted)',
                          textTransform: 'uppercase',
                          letterSpacing: '0.4px'
                        }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {invoiceItems.map((item, i) => {
                      const qty = parseFloat(item.quantity) || 1;
                      const unitPrice = parseFloat(item.unitPrice || item.unit_price) || 0;
                      const total = qty * unitPrice;
                      return (
                        <tr key={i} style={{ borderTop: '1px solid var(--border-primary)', background: i % 2 === 0 ? 'transparent' : 'var(--bg-secondary)' }}>
                          <td style={{ padding: '10px 12px', color: 'var(--text-primary)', fontWeight: 500 }}>
                            <div>{item.name || item.description || 'Item'}</div>
                            {item.name && item.description && item.name !== item.description && (
                              <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '2px' }}>{item.description}</div>
                            )}
                          </td>
                          <td style={{ padding: '10px 12px', textAlign: 'right', color: 'var(--text-secondary)', fontWeight: 600 }}>{qty}</td>
                          <td style={{ padding: '10px 12px', textAlign: 'right', color: 'var(--text-secondary)', fontWeight: 600 }}>{formatCurrency(unitPrice, c.currency)}</td>
                          <td style={{ padding: '10px 12px', textAlign: 'right', color: 'var(--text-primary)', fontWeight: 700 }}>{formatCurrency(total, c.currency)}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                  <tfoot>
                    <tr style={{ borderTop: '2px solid var(--border-primary)', background: 'var(--bg-secondary)' }}>
                      <td colSpan={3} style={{ padding: '10px 12px', textAlign: 'right', fontWeight: 700, color: 'var(--text-primary)', fontSize: '12px', textTransform: 'uppercase' }}>Total</td>
                      <td style={{ padding: '10px 12px', textAlign: 'right', fontWeight: 800, color: 'var(--accent)', fontSize: '14px' }}>
                        {formatCurrency(c.amount, c.currency)}
                      </td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );

  return createPortal(modal, document.body);
};

const CheckoutPage = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedCheckout, setSelectedCheckout] = useState(null);
  const [isDetailsModalOpen, setIsDetailsModalOpen] = useState(false);
  const [checkouts, setCheckouts] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [pagination, setPagination] = useState({
    currentPage: 1,
    totalPages: 1,
    totalItems: 0,
    itemsPerPage: 15
  });

  // Date filters with 2-month default range
  const getTwoMonthsAgo = () => {
    const date = new Date();
    date.setMonth(date.getMonth() - 2);
    return date.toISOString().split('T')[0];
  };

  const getToday = () => {
    return new Date().toISOString().split('T')[0];
  };

  const [dateFilters, setDateFilters] = useState({
    startDate: getTwoMonthsAgo(),
    endDate: getToday()
  });

  // Get user type and user_guid
  const userData = tokenService.getUserData();
  const userType = (userData?.usertype || userData?.user_type || '').toLowerCase();
  const isBusiness = userType === 'business_contact' || userType === 'business_member';
  const userGuid = userData?.user_guid ||
    userData?.userGuid ||
    userData?.id ||
    userData?.userId ||
    userData?.user_id ||
    userData?.customerId ||
    userData?.customer_id;

  // Validate date range (max 2 months)
  const validateDateRange = (startDate, endDate) => {
    const start = new Date(startDate);
    const end = new Date(endDate);
    const diffTime = Math.abs(end - start);
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    const twoMonthsInDays = 61; // Approximately 2 months

    if (diffDays > twoMonthsInDays) {
      return false;
    }
    return true;
  };

  // Fetch checkouts
  const fetchCheckouts = async (page = 1) => {
    if (!userGuid) {
      logger.warn('User GUID not found, cannot fetch checkouts');
      return;
    }

    if (!validateDateRange(dateFilters.startDate, dateFilters.endDate)) {
      showError(t('dateRangeExceeded', {
        ns: 'collections',
        defaultValue: 'Date range cannot exceed 2 months'
      }));
      return;
    }

    setIsLoading(true);
    try {
      const response = await checkoutService.fetchCheckoutCollections({
        user_guid: userGuid,
        start_date: dateFilters.startDate,
        end_date: dateFilters.endDate,
        page,
        limit: pagination.itemsPerPage
      });

      logger.debug('Checkout collections fetched', { response });

      // Handle response data structure
      const data = response?.data || response?.Data || [];
      const checkoutData = Array.isArray(data) ? data : [];

      // Sort: Pending/Processing first (1), then Success/Completed/Paid (2), then other statuses (3).
      // Within each status priority, sort by created_at date descending.
      const statusPriority = (status) => {
        const s = (status || '').toLowerCase();
        if (s === 'pending' || s === 'processing') return 1;
        if (s === 'completed' || s === 'success' || s === 'paid') return 2;
        return 3;
      };

      const sortedCheckouts = [...checkoutData].sort((a, b) => {
        const priorityA = statusPriority(a.status || a.Status);
        const priorityB = statusPriority(b.status || b.Status);

        if (priorityA !== priorityB) {
          return priorityA - priorityB;
        }

        const dateA = new Date(a.created_at || a.createdAt || a.date || 0);
        const dateB = new Date(b.created_at || b.createdAt || b.date || 0);
        return dateB - dateA;
      });

      setCheckouts(sortedCheckouts);

      // Update pagination info
      setPagination(prev => ({
        ...prev,
        currentPage: page,
        totalPages: response?.totalPages || response?.total_pages || Math.ceil((response?.totalItems || response?.total_items || checkoutData.length) / prev.itemsPerPage),
        totalItems: response?.totalItems || response?.total_items || checkoutData.length
      }));

    } catch (error) {
      logger.error('Error fetching checkouts', { error });
      
      const isNoCheckoutFound = 
        error?.code === '05' || 
        error?.data?.code === '05' || 
        error?.response?.data?.code === '05' ||
        error?.message?.includes('No checkout found') ||
        error?.message?.includes('No checkouts found');

      if (isNoCheckoutFound) {
        setCheckouts([]);
      } else {
        showError(t('errorFetchingCheckouts', {
          ns: 'collections',
          defaultValue: 'Failed to fetch checkouts'
        }));
        setCheckouts([]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  // Initial fetch
  useEffect(() => {
    if (userGuid) {
      fetchCheckouts(1);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [userGuid]);

  // Handle date filter change
  const handleDateFilterChange = (field, value) => {
    setDateFilters(prev => ({
      ...prev,
      [field]: value
    }));
  };

  // Apply filters
  const handleApplyFilters = () => {
    fetchCheckouts(1);
  };

  // Handle pagination
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= pagination.totalPages) {
      fetchCheckouts(newPage);
    }
  };

  const handleOpenModal = () => {
    logger.debug('Opening Generate Checkout Modal');
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
  };

  const handleCheckoutSuccess = () => {
    setIsModalOpen(false);
    // Refresh the checkout list
    fetchCheckouts(pagination.currentPage);
  };

  // Format currency
  const formatCurrency = (amount, currency = 'GHS') => {
    if (!amount && amount !== 0) return `${currency} 0.00`;
    return `${currency} ${parseFloat(amount).toFixed(2)}`;
  };

  // Copy checkout link to clipboard
  const handleCopyLink = (url) => {
    if (url) {
      navigator.clipboard.writeText(url);
      success(t('linkCopied', { ns: 'collections', defaultValue: 'Checkout link copied!' }));
    }
  };

  const handleOpenDetails = (checkout) => {
    setSelectedCheckout(checkout);
    setIsDetailsModalOpen(true);
  };

  const handleCloseDetails = () => {
    setSelectedCheckout(null);
    setIsDetailsModalOpen(false);
  };

  // Safe invoice items parser
  const parseInvoiceItems = (itemsJson) => {
    if (!itemsJson) return [];
    try {
      const parsed = typeof itemsJson === 'string' ? JSON.parse(itemsJson) : itemsJson;
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      logger.warn('Failed to parse invoice items', { itemsJson, error: e });
      return [];
    }
  };

  // Format date
  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    try {
      return new Date(dateString).toLocaleDateString('en-GB', {
        day: '2-digit',
        month: 'short',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (error) {
      return dateString;
    }
  };

  // Get status badge style
  const getStatusStyle = (status) => {
    const statusLower = (status || '').toLowerCase();
    switch (statusLower) {
      case 'completed':
      case 'success':
      case 'paid':
        return {
          background: 'rgba(34, 197, 94, 0.1)',
          color: 'var(--success)',
          text: 'Completed'
        };
      case 'pending':
      case 'processing':
        return {
          background: 'rgba(245, 158, 11, 0.1)',
          color: 'var(--warning)',
          text: 'Pending'
        };
      case 'failed':
      case 'cancelled':
      case 'expired':
        return {
          background: 'rgba(239, 68, 68, 0.1)',
          color: 'var(--error)',
          text: 'Failed'
        };
      default:
        return {
          background: 'rgba(156, 163, 175, 0.1)',
          color: 'var(--text-muted)',
          text: status || 'Unknown'
        };
    }
  };

  return (
    <div className="checkout-page">
      <div className="checkout-container">
        {/* Page Header */}
        <div className="checkout-header">
          <div className="checkout-header-content" style={{
            textAlign: 'center'
          }}>
            <h1 className="checkout-title">
              {t('checkout', { ns: 'common', defaultValue: 'Checkout' })}
            </h1>
            <p className="checkout-subtitle">
              {isBusiness
                ? t('businessCheckoutDescription', {
                  ns: 'collections',
                  defaultValue: 'Create and manage payment collection links for your business transactions'
                })
                : t('individualCheckoutDescription', {
                  ns: 'collections',
                  defaultValue: 'Generate secure payment links to receive payments from customers'
                })}
            </p>
          </div>
          <button
            className="checkout-btn-primary"
            onClick={handleOpenModal}
            aria-label={t('generateCheckout', { ns: 'dashboard', defaultValue: 'Generate Checkout' })}
          >
            <span className="material-symbols-outlined">add</span>
            {t('generateCheckout', { ns: 'dashboard', defaultValue: 'Generate Checkout' })}
          </button>
        </div>

        {/* Date Filters */}
        <div style={{
          background: 'var(--card)',
          borderRadius: '12px',
          padding: '20px',
          marginBottom: '24px',
          border: '1px solid var(--border-primary)'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'flex-end',
            gap: '16px',
            flexWrap: 'wrap'
          }}>
            <div style={{ flex: '1', minWidth: '200px' }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                fontWeight: 600,
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                {t('startDate', { ns: 'common', defaultValue: 'Start Date' })}
              </label>
              <input
                type="date"
                value={dateFilters.startDate}
                onChange={(e) => handleDateFilterChange('startDate', e.target.value)}
                max={dateFilters.endDate}
                style={{
                  width: '100%',
                  padding: '12px 16px',
                  fontSize: '14px',
                  borderRadius: '8px',
                  border: '2px solid var(--border-secondary)',
                  background: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                  boxSizing: 'border-box'
                }}
              />
            </div>

            <div style={{ flex: '1', minWidth: '200px' }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                fontWeight: 600,
                color: 'var(--text-primary)',
                fontSize: '14px'
              }}>
                {t('endDate', { ns: 'common', defaultValue: 'End Date' })}
              </label>
              <input
                type="date"
                value={dateFilters.endDate}
                onChange={(e) => handleDateFilterChange('endDate', e.target.value)}
                min={dateFilters.startDate}
                max={getToday()}
                style={{
                  width: '100%',
                  padding: '12px 16px',
                  fontSize: '14px',
                  borderRadius: '8px',
                  border: '2px solid var(--border-secondary)',
                  background: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                  boxSizing: 'border-box'
                }}
              />
            </div>

            <button
              onClick={handleApplyFilters}
              disabled={isLoading}
              style={{
                padding: '12px 24px',
                borderRadius: '8px',
                border: 'none',
                background: isLoading ? 'var(--bg-tertiary)' : 'var(--accent)',
                color: isLoading ? 'var(--text-muted)' : 'var(--text-inverse)',
                fontSize: '14px',
                fontWeight: 600,
                cursor: isLoading ? 'not-allowed' : 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                transition: 'all var(--transition-base)'
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>
                {isLoading ? 'hourglass_top' : 'filter_alt'}
              </span>
              {isLoading ? t('loading', { ns: 'common', defaultValue: 'Loading...' }) : t('applyFilters', { ns: 'common', defaultValue: 'Apply Filters' })}
            </button>
          </div>

          <p style={{
            marginTop: '12px',
            marginBottom: 0,
            fontSize: '12px',
            color: 'var(--text-muted)'
          }}>
            <span className="material-symbols-outlined" style={{ fontSize: '14px', verticalAlign: 'middle', marginRight: '4px' }}>
              info
            </span>
            {t('dateRangeNote', { ns: 'collections', defaultValue: 'Date range is set to 2 months by default' })}
          </p>
        </div>

        {/* Content Section */}
        <div className="checkout-content">
          {/* Your Checkouts Section */}
          <div className="checkout-section">
            <div className="section-header">
              <h2 className="section-title">
                {t('yourCheckouts', { ns: 'collections', defaultValue: 'Your Checkouts' })}
              </h2>
              {pagination.totalItems > 0 && (
                <span style={{
                  fontSize: '14px',
                  color: 'var(--text-muted)',
                  fontWeight: 500
                }}>
                  {t('totalItems', {
                    ns: 'common',
                    defaultValue: `${pagination.totalItems} items`,
                    count: pagination.totalItems
                  })}
                </span>
              )}
            </div>

            {isLoading ? (
              <div style={{
                padding: '60px 20px',
                textAlign: 'center'
              }}>
                <LoadingSpinner size="large" />
                <p style={{ marginTop: '16px', color: 'var(--text-muted)' }}>
                  {t('loadingCheckouts', { ns: 'collections', defaultValue: 'Loading checkouts...' })}
                </p>
              </div>
            ) : checkouts.length > 0 ? (
              <>
                {/* Checkout Grid */}
                <div style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))',
                  gap: '12px',
                  marginTop: '12px'
                }}>
                  {checkouts.map((checkout, index) => {
                    const statusStyle = getStatusStyle(checkout.status || checkout.Status);
                    const customerName = checkout.first_name || checkout.last_name
                      ? `${checkout.first_name || ''} ${checkout.last_name || ''}`.trim()
                      : checkout.customer_name || checkout.customer || checkout.email_name || 'N/A';
                    const sessionUrl = checkout.session_url || checkout.sessionUrl;
                    const items = parseInvoiceItems(checkout.invoice_items);
                    const itemsSummary = items.length > 0
                      ? `${items.length} item${items.length > 1 ? 's' : ''}: ${items.map(i => i.name || i.description || 'Item').join(', ')}`
                      : 'No items listed';

                    return (
                      <div
                        key={checkout.id || checkout.session_id || index}
                        style={{
                          background: 'var(--card)',
                          borderRadius: '10px',
                          border: '1px solid var(--border-primary)',
                          padding: '14px',
                          display: 'flex',
                          flexDirection: 'column',
                          gap: '8px',
                          boxShadow: '0 2px 4px rgba(0,0,0,0.04)',
                          transition: 'all 0.2s ease-in-out',
                          cursor: 'pointer'
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.transform = 'translateY(-3px)';
                          e.currentTarget.style.borderColor = 'var(--accent)';
                          e.currentTarget.style.boxShadow = '0 8px 16px rgba(0,0,0,0.1)';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.transform = 'translateY(0)';
                          e.currentTarget.style.borderColor = 'var(--border-primary)';
                          e.currentTarget.style.boxShadow = '0 2px 4px rgba(0,0,0,0.04)';
                        }}
                        onClick={() => handleOpenDetails(checkout)}
                      >
                        {/* Header: Ref + Status */}
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <span style={{
                            fontFamily: 'monospace',
                            fontSize: '11px',
                            fontWeight: 600,
                            color: 'var(--text-muted)',
                            background: 'var(--bg-secondary)',
                            padding: '3px 6px',
                            borderRadius: '4px'
                          }}>
                            #{(checkout.reference_id || checkout.referenceid || 'N/A').substring(0, 8)}
                          </span>
                          <span style={{
                            padding: '3px 8px',
                            borderRadius: '20px',
                            fontSize: '10px',
                            fontWeight: 700,
                            textTransform: 'uppercase',
                            background: statusStyle.background,
                            color: statusStyle.color
                          }}>
                            {statusStyle.text}
                          </span>
                        </div>

                        {/* Amount */}
                        <div style={{ fontSize: '20px', fontWeight: 800, color: 'var(--text-primary)', lineHeight: 1.1 }}>
                          {formatCurrency(checkout.amount, checkout.currency)}
                        </div>

                        {/* Narration */}
                        <div style={{ fontSize: '12px', color: 'var(--text-secondary)', fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                          {checkout.narration || 'Payment Collection'}
                        </div>

                        {/* Customer + Date */}
                        <div style={{ borderTop: '1px solid var(--border-primary)', paddingTop: '8px', display: 'flex', flexDirection: 'column', gap: '4px' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '12px', color: 'var(--text-secondary)' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>person</span>
                            <span style={{ fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{customerName}</span>
                          </div>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '11px', color: 'var(--text-muted)' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>calendar_today</span>
                            <span>{formatDate(checkout.created_at || checkout.createdAt || checkout.date)}</span>
                          </div>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '11px', color: 'var(--text-muted)' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>shopping_bag</span>
                            <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{itemsSummary}</span>
                          </div>
                        </div>

                        {/* Click hint */}
                        <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                          <span style={{ fontSize: '10px', color: 'var(--accent)', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '3px' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '13px' }}>info</span>
                            View Details
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Pagination */}
                {pagination.totalPages > 1 && (
                  <div style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    marginTop: '24px',
                    flexWrap: 'wrap',
                    gap: '16px'
                  }}>
                    <div style={{
                      fontSize: '14px',
                      color: 'var(--text-muted)'
                    }}>
                      {t('pageInfo', {
                        ns: 'common',
                        defaultValue: `Page ${pagination.currentPage} of ${pagination.totalPages}`
                      })}
                    </div>

                    <div style={{
                      display: 'flex',
                      gap: '8px'
                    }}>
                      <button
                        onClick={() => handlePageChange(1)}
                        disabled={pagination.currentPage === 1}
                        style={{
                          padding: '8px 12px',
                          borderRadius: '6px',
                          border: '1px solid var(--border-secondary)',
                          background: pagination.currentPage === 1 ? 'var(--bg-tertiary)' : 'var(--card)',
                          color: pagination.currentPage === 1 ? 'var(--text-muted)' : 'var(--text-primary)',
                          cursor: pagination.currentPage === 1 ? 'not-allowed' : 'pointer',
                          fontSize: '14px',
                          fontWeight: 500
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                          first_page
                        </span>
                      </button>

                      <button
                        onClick={() => handlePageChange(pagination.currentPage - 1)}
                        disabled={pagination.currentPage === 1}
                        style={{
                          padding: '8px 12px',
                          borderRadius: '6px',
                          border: '1px solid var(--border-secondary)',
                          background: pagination.currentPage === 1 ? 'var(--bg-tertiary)' : 'var(--card)',
                          color: pagination.currentPage === 1 ? 'var(--text-muted)' : 'var(--text-primary)',
                          cursor: pagination.currentPage === 1 ? 'not-allowed' : 'pointer',
                          fontSize: '14px',
                          fontWeight: 500
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                          chevron_left
                        </span>
                      </button>

                      <button
                        onClick={() => handlePageChange(pagination.currentPage + 1)}
                        disabled={pagination.currentPage === pagination.totalPages}
                        style={{
                          padding: '8px 12px',
                          borderRadius: '6px',
                          border: '1px solid var(--border-secondary)',
                          background: pagination.currentPage === pagination.totalPages ? 'var(--bg-tertiary)' : 'var(--card)',
                          color: pagination.currentPage === pagination.totalPages ? 'var(--text-muted)' : 'var(--text-primary)',
                          cursor: pagination.currentPage === pagination.totalPages ? 'not-allowed' : 'pointer',
                          fontSize: '14px',
                          fontWeight: 500
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                          chevron_right
                        </span>
                      </button>

                      <button
                        onClick={() => handlePageChange(pagination.totalPages)}
                        disabled={pagination.currentPage === pagination.totalPages}
                        style={{
                          padding: '8px 12px',
                          borderRadius: '6px',
                          border: '1px solid var(--border-secondary)',
                          background: pagination.currentPage === pagination.totalPages ? 'var(--bg-tertiary)' : 'var(--card)',
                          color: pagination.currentPage === pagination.totalPages ? 'var(--text-muted)' : 'var(--text-primary)',
                          cursor: pagination.currentPage === pagination.totalPages ? 'not-allowed' : 'pointer',
                          fontSize: '14px',
                          fontWeight: 500
                        }}
                      >
                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                          last_page
                        </span>
                      </button>
                    </div>
                  </div>
                )}
              </>
            ) : (
              <div style={{
                padding: '40px 20px',
                textAlign: 'center',
                color: 'var(--text-muted)'
              }}>
                <span className="material-symbols-outlined" style={{
                  fontSize: '48px',
                  opacity: 0.5,
                  marginBottom: '16px',
                  display: 'block'
                }}>
                  shopping_cart
                </span>
                <p style={{ margin: 0 }}>
                  {t('noCheckouts', { ns: 'collections', defaultValue: 'No checkouts found for the selected date range' })}
                </p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Generate Checkout Modal */}
      <GenerateCheckoutLinkModal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        onSuccess={handleCheckoutSuccess}
      />

      {/* Checkout Details Modal */}
      <CheckoutDetailsModal
        checkout={isDetailsModalOpen ? selectedCheckout : null}
        onClose={handleCloseDetails}
        formatCurrency={formatCurrency}
        formatDate={formatDate}
        parseInvoiceItems={parseInvoiceItems}
        getStatusStyle={getStatusStyle}
        handleCopyLink={handleCopyLink}
      />
    </div>
  );
};

export default CheckoutPage;
